import{_ as l,c as t,o as a,ae as o}from"./chunks/framework.NcZqgvTs.js";const s="/logo.png",g=JSON.parse('{"title":"鶯歌老街尋寶記：體驗陶瓷藝術與美食之旅","description":"","frontmatter":{},"headers":[],"relativePath":"blog/2025-05-23.md","filePath":"blog/2025-05-23.md"}'),i={name:"blog/2025-05-23.md"};function p(r,e,c,n,m,_){return a(),t("div",null,e[0]||(e[0]=[o('<p>title: 鶯歌老街尋寶記：體驗陶瓷藝術與美食之旅 date: 2025-05-25 description: 這次聖小熊要帶大家來到充滿藝術氣息的新北市鶯歌區，一起逛逛熱鬧的鶯歌老街，感受陶瓷文化的魅力，並品嚐在地特色美食！ tag: # 您可以為文章加上標籤</p><ul><li>鶯歌</li><li>老街</li><li>陶瓷</li><li>美食</li><li>台灣旅遊 category:</li><li>旅遊</li></ul><hr><h1 id="鶯歌老街尋寶記-體驗陶瓷藝術與美食之旅" tabindex="-1">鶯歌老街尋寶記：體驗陶瓷藝術與美食之旅 <a class="header-anchor" href="#鶯歌老街尋寶記-體驗陶瓷藝術與美食之旅" aria-label="Permalink to &quot;鶯歌老街尋寶記：體驗陶瓷藝術與美食之旅&quot;">​</a></h1><p>嗨，大家好！這次聖小熊要帶大家來到充滿藝術氣息的新北市鶯歌區，一起逛逛熱鬧的鶯歌老街，感受陶瓷文化的魅力，並品嚐在地特色美食！</p><p>鶯歌，這個以陶瓷聞名的小鎮，擁有悠久的製陶歷史。一踏進老街，兩旁琳瑯滿目的陶瓷藝品店立刻吸引了我的目光。從精緻的茶具、古樸的花瓶，到可愛的裝飾品，每一件都散發著獨特的藝術光彩，讓人愛不釋手。</p><p><img src="https://shoplineimg.com/5e82ba489e08ce0053908f85/67a5b0e10ea626000dc6d800/800x.webp" alt="鶯歌老街的陶瓷藝品"><small style="display:block;text-align:center;color:#777;">老街上各式各樣的精美陶瓷藝品，令人目不暇給。</small></p><p>走在老街的紅磚道上，不時可以看到師傅們在工作室裡專注地製作陶瓷。那份對傳統工藝的堅持與熱愛，令人由衷敬佩。許多店家也提供 DIY 陶瓷體驗，讓遊客可以親手製作獨一無二的紀念品，非常適合親子同樂。</p><p><img src="'+s+'" alt="體驗手拉坯的樂趣"><small style="display:block;text-align:center;color:#777;">親手體驗手拉坯的樂趣，感受泥土的溫度。</small></p><p>除了陶瓷，鶯歌的美食也是不容錯過的。老街上有許多傳統小吃和特色餐廳。我品嚐了香Q彈牙的<strong>阿婆壽司</strong>，還有濃郁入味的<strong>古早味肉羹</strong>，每一口都充滿了在地風味，讓人回味無窮。</p><p><img src="https://shoplineimg.com/5e82ba489e08ce0053908f85/67a5b0e10ea626000dc6d800/800x.webp" alt="鶯歌在地美食"><small style="display:block;text-align:center;color:#777;">鶯歌老街的傳統美食，簡單卻美味。</small></p><p>這次的鶯歌老街尋寶之旅，不僅讓我欣賞到精美的陶瓷藝術，也品嚐到了道地的台灣味。如果你也想體驗一趟充滿文化與美食的旅程，不妨找個時間來鶯歌走走吧！</p>',12)]))}const b=l(i,[["render",p]]);export{g as __pageData,b as default};
